INSERT INTO allah_names VALUES(1,'He who wills goodness and mercy for all His creatures','The Beneficent','(1:3)(17:110)','الرَّحْمَنُ','Ar Rahmaan','আর-রাহমান','পরম করুণাময়',NULL);
INSERT INTO allah_names VALUES(2,'He who acts with extreme kindness ','The Merciful','(2:163) (3: 31) (4:100) (5:3)','الرَّحِيمُ','Ar Raheem','আর-রাহীম','অফুরন্ত দাতা / অতি দয়ালু','');
INSERT INTO allah_names VALUES(3,'The Sovereign Lord, The One with the complete Dominion, the One Whose Dominion is clear from imperfection ','The King / Eternal Lord','(20:114)(23:116)(59:23)(62:1)','الْمَلِكُ','Al Malik','আল-মালিক','রাজাধিরাজ','');
INSERT INTO allah_names VALUES(4,'The One who is pure from any imperfection and clear from children and adversaries','The Purest','(59:23) (62:1)','الْقُدُّوسُ','Al Quddus','আল-কুদ্দুস','সমস্ত সন্দেহ-সংশয় মুক্ত সত্তা','');
INSERT INTO allah_names VALUES(5,'The one who provides peace, calm and serenity. By citing this name, we declare peace for ourselves and for those around us.','The Source of Peace','(59:23)','السَّلاَمُ','As Salaam','আস-সালাম','প্রশান্তিদাতা','');
INSERT INTO allah_names VALUES(6,'This name is mysterious even for Muslims because \"Al-Mu''min\" comes from the name \"Al-iman\" which means to believe, from where comes the name \"Al-Mu''minoune\" which means believers, it is is the name of the Koran for people who believe in 6 things: the oneness of God, the existence of angels, holy books (Torah, Gospel and Psalms (Zabor) unmodified and the Koran), the prophets, the last day (the day of judgment) and fate its evil and its good. The exact meaning of this name is very difficult to pin down in its original meaning but can be understood from a deeper and more mystical point of view.','The inspirer of faith','(59:23)','الْمُؤْمِنُ','Al Mu''min','আল-মুমিন','নিরাপত্তাদাতা','');
INSERT INTO allah_names VALUES(7,'Whoever dominates His creation and by His omnipotence in all aspects, no state or aspect in this world or the other escapes His will.','The Guardian','(59:23)','الْمُهَيْمِنُ','Al Muhaymin','আল-মুহাইমিন','অভিভাবক','');
INSERT INTO allah_names VALUES(8,'The Glorious by His supremacy and His greatness, El-Aziz means in a sense the one who is dear and precious in the eyes of His creatures. He is not the servant of any creature, and no creature dictates to him what to do.','The Precious / The Most Mighty','(3:6)(4:15 8)(9:40)(4 8:7)','الْعَزِيزُ','Al Azeez','আল-আযীয','প্রবল পরাক্রমশালী','');
INSERT INTO allah_names VALUES(9,'The grandiose, the ultimate powerful by His greatness and His unlimited strength. When He destroys the oppressors (unjust and sinners) He applies His sentence with righteousness.','The Compeller','(59:23)','الْجَبَّارُ','Al Jabbaar','আল-জাব্বার','সবচেয়ে মহান ও ক্ষমতাশালী','');
INSERT INTO allah_names VALUES(10,'He who is superior to His creatures, no creature has the right to claim greatness.','The Greatest','(59:23)','الْمُتَكَبِّرُ','Al Mutakabbir','আল-মুতাকাব্বির','মহত্বের অধিকারী','');
INSERT INTO allah_names VALUES(11,'The Creator of all existences, living or dead, mobile or frozen.','The Creator','(6:102)(13:16)(39:62)(40:62)(59:24)','الْخَالِقُ','Al Khaaliq','আল-খালিক','সৃষ্টিকর্তা','');
INSERT INTO allah_names VALUES(12,'He who lifts His creation above all faults or imperfections.','The Maker of Order','(59:24)','الْبَارِئُ','Al Baari','আল-বারী','প্রাণদাতা','');
INSERT INTO allah_names VALUES(13,'The one who gives the look and the appearance to each creation from the inside as well as from the outside. In lost Arabic, literally, this word means sculptor and, in modern Arabic, literally means designer.','The Shaper of Beauty','(59:24)','الْمُصَوِّرُ','Al Musawwir','আল-মুসাউয়ির','আকৃতি দানকারী','');
INSERT INTO allah_names VALUES(14,'Is the One who forgives what He wants to whom He wants.','The Forgiving','(20:82)(38:66)(39:5)(40:42)(71:10)','الْغَفَّارُ','Al Ghaffaar','আল-গাফ্ফার','ক্ষমাশীল','');
INSERT INTO allah_names VALUES(15,'Is the One who is almighty to submit all creation to His will.','The Subduer','(13:16)(14:48)(38:65)(39:4)(40:16)','الْقَهَّارُ','Al Qahhaar','আল-কাহ্‌হার','মহা শাস্তিদানকারী','');
INSERT INTO allah_names VALUES(16,'Is the One who gives immensely without receiving anything in return','The Giver of All','(3:8)(38:9)(38:35)','الْوَهَّابُ','Al Wahhaab','আল-ওয়াহাব','অত্যন্ত দাতা','');
INSERT INTO allah_names VALUES(17,'Is the One who makes distribute to every creature what it needs.','The Sustainer','(51:58)','الرَّزَّاقُ','Ar Razzaaq','আর-রায্‌যাক','রিযিকদাতা','');
INSERT INTO allah_names VALUES(18,'Is He Who alone knows the keys to the future and the unknown, by His knowledge and by His wisdom. This name is often associated with the following name "Al-‘Alīm".','The Opener','(34:26)','الْفَتَّاحُ','Al Fattaah','আল-ফাত্তাহ','Lবিজয় দানকারী','');
INSERT INTO allah_names VALUES(19,'The one from whom nothing can hide, for He knows everything and is aware of everything.','The Knower of all','(2:158)(3:92)(4:35)(24:41)(33:40)','اَلْعَلِيْمُ','Al ''Aleem','আল-আলীম','সর্বজ্ঞ','');
INSERT INTO allah_names VALUES(20,'Is the One who restricts His good according to wisdom.','The Constrictor','(2:245)','الْقَابِضُ','Al Qaabid','আল-কাবীদ','রিযিক সংকীর্ণকারী','');
INSERT INTO allah_names VALUES(21,'Is the One who frees, increases and multiplies his good according to wisdom.','The Reliever','(2:245)','الْبَاسِطُ','Al Baasit','আল-বাসিত','রিযিক প্রশস্তকারী','');
INSERT INTO allah_names VALUES(22,'Is the One who destines the oppressors and the proud to demeanor and chastisement.','The Abaser','(95:5)','الْخَافِضُ','Al Khaafid','আল-খাফিদ','অবনতকারী','');
INSERT INTO allah_names VALUES(23,'The Breeder in the sense of raising, the one who elevates the honor, the status and the prestige of a being in this lower world and in the hereafter.','The Exalter','(58:11)(6:83)','الرَّافِعُ','Ar Raafi''','আর-রাফি','উন্নতি প্রদানকারী','');
INSERT INTO allah_names VALUES(24,'One who offers honor and precious value.','The Bestower of Honour','(3:26)','الْمُعِزُّ','Al Mu''iz','আল-মু্য়িজ','সম্মানদাতা','');
INSERT INTO allah_names VALUES(25,'Is the One who can humiliate and devalue any valiant.','The Humiliator','(3:26)','المُذِلُّ','Al Mudhil','আল-মুধীল','অপমানদাতা','');
INSERT INTO allah_names VALUES(26,'One who hears any noise or sound in His kingdom emanating from any creature and also One who listens to the invocations of His creatures to respond to their invocations.','The Hearer of all','(2:127)(2:256)(8:17)(49:1)','السَّمِيعُ','As Samee''','আস-সামী','সর্বশ্রোতা','');
INSERT INTO allah_names VALUES(27,'Is the One from whom nothing that exists or comes into existence can escape without the slightest use of an eye, instrument or organ.','The Seer of all','(4:58)(17:1)(42:11)(42:27)','الْبَصِيرُ','Al Baseer','আল-বাসীর','সর্বদ্রষ্টা','');
INSERT INTO allah_names VALUES(28,'He is the One who judges and decides between creatures here below and in the hereafter and He who ensures equity between the creatures and no one else will and will not be able to decide between them and judge them; and the Judgment in the hereafter will be perfectly just and appropriate.','The Judge','(22:69)','الْحَكَمُ','Al Hakam','আল-হাকাম','বিচারক','');
INSERT INTO allah_names VALUES(29,'Is the One who is free from all forms of injustice and / or oppression.','The Just','(6:115)','الْعَدْلُ','Al ''Adl','আল-আদল','ন্যায়বিচারক','');
INSERT INTO allah_names VALUES(30,'Is the One who grants his creatures His gentleness and His benevolence.','The Subtle One','(6:103)(22:63)(31:16)(33:34)','اللَّطِيفُ','Al Lateef','আল-লাতিফ','Lঅতি অনুগ্রহশীল','');
INSERT INTO allah_names VALUES(31,'He is the One from whom cannot be hidden the reality of everything that exists, that is to say the truth of things; no detail escapes Him, neither the thing as a whole, nor each of its parts; and to claim to be able to hide things from the One who creates everything is a delusion and a disbelief.','The All Aware','(6:18)(17:30)(49:13)(59:18)','الْخَبِيرُ','Al Khabeer','আল-খাবির','সর্ববিষয়ে জ্ঞানী','');
INSERT INTO allah_names VALUES(32,'Is the One whose patience towards the disbeliefs of sinners exceeds all imagination (it is possible that forgiveness will be granted to them).','The Forebearing','(2:235)(17:44)(22:59)(35:41)','الْحَلِيمُ','Al Haleem','আল-হালিম','মহা ধৈর্যশীল','');
INSERT INTO allah_names VALUES(33,'This name is difficult to translate because it includes several French words that do not share the same spiritual meaning, but it can be approached as follows: "Al-Adhīm" He who is Gigantic Majestic and Fantastically Grandiose far from any bodily or material imperfection','The Maginificent','(2:255)(42:4)(56:96)','الْعَظِيمُ','Al ''Azeem','আল-আযীম','অতি মহান','');
INSERT INTO allah_names VALUES(34,'Is the One who forgives immensely over and over again.','The Great Forgiver','(2:173)(8:69)(16:110)(41:32)','الْغَفُورُ','Al Ghafoor','আল-গাফুর','অত্যন্ত ক্ষমাশীল','');
INSERT INTO allah_names VALUES(35,'Is the One who shows His gratitude for worshipers, however incredibly easy to perform.','The Rewarder of Thankfulness','(35:30)(35:34)(42:23)(64:17)','الشَّكُورُ','Ash Shakoor','আশ-শাকুর','ভালো কাজের পুরষ্কারদানকারী / গুণগ্রাহী','');
INSERT INTO allah_names VALUES(36,'Is the One who is above all that He created perfectly and unimaginably.','The Highest','(4:34)(31:30)(42:4)(42:51)','الْعَلِيُّ','Al ''Aliyy','আল-আলী','Lসর্বোচ্চ','');
INSERT INTO allah_names VALUES(37,'The Great: One who is greater than His creation, a greatness that only He knows.','The Greatest','(13:9)(22:62)(31:30)','الْكَبِيرُ','Al Kabeer','আল-কাবির','সর্বোচ্চ মর্যাদাবান','');
INSERT INTO allah_names VALUES(38,'Is the One who protects and preserves His good.','The Preserver','(11:57)(34:21)(42:6)','الْحَفِيظُ','Al Hafeez','আল-হাফীয','সবকিছুর সংরক্ষক','');
INSERT INTO allah_names VALUES(39,'this word is among the lost words of the ancient Arabic language; very difficult to translate even in modern Arabic}. It would mean: Is the One who leaves no detail when He judges, even the most trivial.','The Sustainer','(4:85)','المُقيِت','Al Muqeet','আল-মুকীত','অন্ন ও শক্তিদাতা','');
INSERT INTO allah_names VALUES(40,'He is the One who will count all the facts of His creatures without forgetting or error.','The Reckoner, The Sufficient','(4:6)(4:86)(33:39)','الْحسِيبُ','Al Haseeb','আল-হাসিব','হিসাব গ্রহণকারী','');
INSERT INTO allah_names VALUES(41,'Is the One who is perfectly exempt from being compared to His creatures or from being like Him.','The Majestic','(55:27)(39:14)(7:143)','الْجَلِيلُ','Al Jaleel','আল-জালীল','অতি মর্যাদাবান','');
INSERT INTO allah_names VALUES(42,'Is the One who flooded His creation with His generosity.','The Most Generous, The Most Esteemed','(27:40)(82:6)','الْكَرِيمُ','Al Kareem','আল-কারীম','অনুগ্রহকারী','');
INSERT INTO allah_names VALUES(43,'Is the One who observes and beholds all that He has created (and the actions of creatures are also creations).','The Watchful One','(4:1)(5:117)','الرَّقِيبُ','Ar Raqeeb','আর-রাকীব','তত্ত্বাবধায়ক','');
INSERT INTO allah_names VALUES(44,'Is the One who answers the invocations of His creatures if He wills and to whom He wills.','The Responder to Prayer','(11:61)','الْمُجِيبُ','Al Mujeeb ','আল-মুজিব','দুআ কবুলকারী','');
INSERT INTO allah_names VALUES(45,'This name in Arabic means: immensely wide, but to qualify God it is understood that He has filled every void and has contained all things in a way that only He knows.','The All-Encompassing, the Boundless','(2:268)(3:73)(5:54)','الْوَاسِعُ','Al Waasi''','আল-ওয়াসি','অসীম, সর্বত্র বিরাজমান','');
INSERT INTO allah_names VALUES(46,'He whose Wisdom has dazzled, dazzled and will dazzle any conscious and intelligent mind.','The Perfectly Wise','(31:27)(46:2)(57:1)(66:2)','الْحَكِيمُ','Al Hakeem','আল-হাকিম','সুবিজ্ঞ, সুদক্ষ','');
INSERT INTO allah_names VALUES(47,'This word in Arabic means: The one who draws near to his beloved by mercy, pity and beneficence, but when one reads this name in the "Koran", one feels each time different meanings which are difficult to translate into words}. We can try to translate it: The one who draws near to His servants out of pity although they move away from Him and do not glorify Him.','The Most Loving','(11:90)(85:14)','الْوَدُودُ','Al Wudood','আল-ওয়াদুদ','ভালবাসা পোষণকারী','');
INSERT INTO allah_names VALUES(48,'Is the One who is glorified in the infinitely past, present and eternal.','The Glorious One, The Most Honorable','(11:73) ','الْمَجِيدُ','Al Majeed','আল-মাজীদ','মহত্বের অধিকারী','');
INSERT INTO allah_names VALUES(49,'Is the One who raises the dead and deploys life in whatever He wants, be they men, animals or simply earth.','The Resurrector','(22:7)','الْبَاعِثُ','Al Baa''ith','আল-বায়িত','পুনরুত্থানকারী','');
INSERT INTO allah_names VALUES(50,'The Witness: Allah is the ultimate and perfect witness to all that has happened in His kingdom, with clear and blatant evidence, perfectly blameless.','The Witness','(4:166)(22:17)(41:53)(48:28)','الشَّهِيدُ','Ash Shaheed','আশ-শাহীদ','সর্বত্র বিদ্যমান/সাক্ষী','');
INSERT INTO allah_names VALUES(51,'Is the One who holds the absolute Truth.','The Truth','(6:62)(22:6)(23:116)(24:25)','الْحَقُّ','Al Haqq','আল-হাক্ব','হক ও চিরসত্য','Est Celui qui d\u00E9tient la V\u00E9rit\u00E9 absolue.');
INSERT INTO allah_names VALUES(52,'Is the One who guarantees the sustenance of creatures and the One from whom nothing of their every state can be concealed','The Trustee','(3:173)(4:171)(28:28)(73:9)','الْوَكِيلُ','Al Wakeel','আল-ওয়াকীল','মহাব্যবস্থাপক','');
INSERT INTO allah_names VALUES(53,'The Mighty: Allah is the most powerful, the strongest, his strength has no limit and is not described with definitions of physical strength.','The Possessor of all strength','(22:40)(22:74)(42:19)(57:25)','الْقَوِيُّ','Al Qawiyy','আল-ক্বাবিয়্যু','মহাশক্তিধর','');
INSERT INTO allah_names VALUES(54,'The Enduring: An endurance worthy of Him, unlimited, indefatigable, and which is not marred by any weakness, without pause, without interruption and which no factor can attenuate.','The Forceful','(51:58)','الْمَتِينُ','Al Mateen','আল-মাতিন','অটল / অনড়','');
INSERT INTO allah_names VALUES(55,'Is the One who preserves the believing servants, so the prophets and those who follow them are those who are the "preserved people" in the sense that they have been guided to the obligatory thanks to Him who makes them exist, that is, that is to say with regard to Allah','The Protector','(4:45)(7:196)(42:28)(45:19)','الْوَلِيُّ','Al Waliyy','আল-ওয়ালিয়্যু','বন্ধু ও সাহায্যকারী','');
INSERT INTO allah_names VALUES(56,'Is the One who deserves the thanksgiving, the glorification and the song of praise more than any other','The Praised','(14:8)(31:12)(31:26)(41:42)','الْحَمِيدُ','Al Hameed','আল-হামিদ','প্রশংসিত','');
INSERT INTO allah_names VALUES(57,'Literally translated as the counter but means the One who counts every creature, every act, every speck of dust in his kingdom and of whom nothing escapes his knowledge','The All-Enumerating, The Counter','(72:28)(78:29)(82:10-12)','الْمُحْصِي','Al Muhsi','আল-মুহসি','যার জ্ঞান সবকিছুকে বেষ্টন করে আছে','');
INSERT INTO allah_names VALUES(58,'Is the One who gives a beginning to what does not exist without a beginning, without a model, that is to say, the One who creates creatures','The Originator','(10:34)(27:64)(29:19)(85:13)','الْمُبْدِئُ','Al Mubdi','আল-মুবদি','সৃষ্টির সূচনাকারী','Est Celui qui donne un d\u00E9but \u00E0 ce qui n\u2019existe pas sans d\u00E9but, sans mod\u00E8le, c''est-\u00E0-dire Celui qui cr\u00E9e les cr\u00E9atures ');
INSERT INTO allah_names VALUES(59,'Is the One who brings the living back to death after life and the One who brings the dead back to life after death','The Restorer','(10:34)(27:64)(29:19)(85:13)','الْمُعِيدُ','Al Mu''eed','আল-মুয়িদ','পুনরুজ্জীবিতকারী','');
INSERT INTO allah_names VALUES(60,'Is the One who gives life to a mixture of maniyy, that is to say of seminal liquid, devoid of soul and makes him a living being and the One who gives life to the bodies of humans, jinns and angels by reuniting them with their souls during the resurrection','The Giver of life','(7:158)(15:23)(30:50)(57:2)','الْمُحْيِي','Al Muhiy','আল-মুহ্‌য়ি','জীবনদাতা','');
INSERT INTO allah_names VALUES(61,'He is the One who kills living beings and the One who cancels out the power of the powerful of this world by death','The Taker of life','(3:156)(7:158)(15:23)(57:2)','اَلْمُمِيتُ','Al Mumeet','আল-মুহ্‌য়ি','আল-মুমিত','');
INSERT INTO allah_names VALUES(62,'The Living One: Is the One who does not come into existence and yet exists, and the One who possesses a hayah and this attribute is not a life as is the hayah of creatures made up of a combination of soul, flesh and of blood Imam At-Tahawiyy said in his treatise on belief that "he who attributes to Allah an attribute in a sense which is among those which can be attributed to human beings is disbeliever"','The Ever Living','(2:255)(3:2)(25:58)(40:65)','الْحَيُّ','Al Haiyy','আল-হাই','চিরন্জীব','');
INSERT INTO allah_names VALUES(63,'Is the One who exists, is eternal and does not change and the One who is not affected by non-existence or annihilation and is in no way affected by controlling and creating the acts of human beings','The Self Existing','(2:255)(3:2)(20:111)','الْقَيُّومُ','Al Qayyoom','আল-কাইয়ুম','অমুখাপেক্ষী / সবকিছুর ধারক','');
INSERT INTO allah_names VALUES(64,'Is the One who does not need anything and is not reached or concerned with want, lack or need','The Perceiver','(38:44)','الْوَاجِدُ','Al Waajid','আল-ওয়াজিদ','পর্যবেক্ষক, অব্যর্থ','');
INSERT INTO allah_names VALUES(65,'Is the One who is better than any other and the One who bestows innumerable benefits very widely and without compensation','The Glorious','(11:73)','الْمَاجِدُ','Al Maajid','আল-মাজীদ','মহিমাময়','');
INSERT INTO allah_names VALUES(66,'The Unique: Is the One who has no alter ego, whether in His Being, in His Act, or in His Attributes. Nothing is like him','The Only One','(2:163)(5:73)(9:31)(18:110)','الْواحِدُ','Al Waahid','আল-ওয়াহিদ','এক ও অদ্বিতীয়','');
INSERT INTO allah_names VALUES(67,'The One: Is He Who has uniqueness as an attribute','The One','(112:1)','اَلاَحَدُ','Al Ahad','আল-আহাদ','এক','');
INSERT INTO allah_names VALUES(68,'Is the One to whom we can rely for any business and who can be called upon for all our needs; One who has no children or parents, neither like nor equivalent, according to Al-Hakim''s explanation; The One who needs nothing and the One who everything needs, in order to exist, etc.','The Supreme Provider','(112:2)','الصَّمَدُ','As Samad','আস-সামাদ','অভাবমুক্ত','');
INSERT INTO allah_names VALUES(69,'Is the One who is unaffected by weakness, the One whose power is absolute and dominates all creatures and the One whom absolutely nothing can weaken','The Powerful','(6:65)(36:81)(46:33)(75:40)','الْقَادِرُ','Al Qaadir','আল-কাদির','সবকিছু করতে সক্ষম / সর্বশক্তিমান','');
INSERT INTO allah_names VALUES(70,'Is the One who is mighty over all things and the One whose capacities are absolutely limitless','The Creator of all power','(18:45)(54:42)(54:55)','الْمُقْتَدِرُ','Al Muqtadir','আল-মুক্‌তাদির','সকল ক্ষমতার উৎস','');
INSERT INTO allah_names VALUES(71,'Is He who is free from the characteristics of creatures and better than any creature; He who fixes the speed of events, accelerates certain things in the eyes of people according to a destiny and grants each thing a value, a rank, a time and characteristics which suit Him according to wisdom','The Expediter','(16:61)(17:34)','الْمُقَدِّمُ','Al Muqaddim','আল-মুকাদ্দিম','অগ্রবর্তিকারী','');
INSERT INTO allah_names VALUES(72,'Is He who is free from the characteristics of creatures and better than any creature; The one who intends the slowness of events and slows down certain things in the eyes of people according to a destiny and grants each thing a value, a rank, a time and characteristics which suit it according to a wisdom (cf no 71)','The Delayer','(71:4)','الْمُؤَخِّرُ','Al Mu’akhir','আল-মুয়াখখির','পশ্চাৎবর্তিকারী','');
INSERT INTO allah_names VALUES(73,'The First: Is the One who exists without creatures, without beginning and without time; One who is exempt from being created, from the appearance of a new attribute and from change, One who exists without coming into existence','The First','(57:3)','الأوَّلُ','Al Awwal','আল-আউয়াল','সর্বপ্রথম','');
INSERT INTO allah_names VALUES(74,'The Last: Is the One who exists without interruption while the creatures are annihilated at every moment; He who is eternal, He who annihilates and is exempt from being annihilated and the disappearance of one or more attributes; The one that exists without being concerned by the notion of end and annihilation','The Last','(57:3)','الآخِرُ','Al Aakhir','আল-আখির','অনন্ত / সর্বশেষ','');
INSERT INTO allah_names VALUES(75,'Is the One whose existence is manifested in everything by proofs, from the point of view of power and domination and not what would be present in any body from the point of view of place, image and how','The Manifest','(57:3)','الظَّاهِرُ','Az Zaahir','আয-যাহীর','প্রকাশমান','');
INSERT INTO allah_names VALUES(76,'Is the One who is preserved from the delusions of creatures attempting to attribute to the Creator human characteristics or characteristics of creatures and the One who creates the characteristics of creatures and their images','The Hidden','(57:3)','الْبَاطِنُ','Al Baatin','আল-বাতিন','অদৃশ্য / গুপ্ত','');
INSERT INTO allah_names VALUES(77,'Is the One who owns, manages and controls all things and the One who creates everything according to wisdom','The Governor','(13:11)(22:7)','الْوَالِي','Al Waali','আল-ওয়ালী','তত্তাবধায়ক','');
INSERT INTO allah_names VALUES(78,'Is the One who is free from the attributes of creatures and the One whose power over creatures is boundless','The Supreme One','(13:9)','الْمُتَعَالِي','Al Muta’ali','আল-মুতাআলি','সর্বোচ্চ মর্যাদাবান','');
INSERT INTO allah_names VALUES(79,'Is the One who has the ability to bestow faith and blessings on all creatures, and among them some are grateful and some are not: the former are called Muslims or believers and others are called non-Muslims or non-Muslims. -believers','The Doer of Good','(52:28)','الْبَرُّ','Al Barr','আল-বার্‌রু','পরম উপকারী','');
INSERT INTO allah_names VALUES(80,'Is the One who grants forgiveness to those who repent every time they repent','The Guide to Repentence','(2:128)(4:64)(49:12)(110:3)','التَّوَابُ','At Tawwaab','আত-তাওয়াব','তওবা কবুলকারী','');
INSERT INTO allah_names VALUES(81,'Is the avenger','The Avenger','(32:22)(43:41)(44:16)','الْمُنْتَقِمُ','Al Muntaqim','আল-মুনতাকীম','অপরাধীর শাস্তি দানকরী','');
INSERT INTO allah_names VALUES(82,'Is the One who sets aside and forgives sin and the One who preserves in every seemingly hopeless situation a door to honor, maintenance and blessings or to immediate repentance','The Forgiver','(4:99)(4:149)(22:60) ','العَفُوُّ','Al Afuww','আল-আফুউ','মার্জনাকারী','');
INSERT INTO allah_names VALUES(83,'Is the One who can offer an immensity of benefits without counterpart and without necessity','The Most Kind','(3:30)(9:117)(57:9)(59:10)','الرَّؤُوفُ','Ar Ra’oof','আর-রাউফ','অত্যন্ত দয়ালু','');
INSERT INTO allah_names VALUES(84,'Is the One who creates and attributes according to a destiny all sovereignty, domination, property and all broad power which are granted to certain creatures in this lower world','The Owner / Soverign of All','(3:26)','مَالِكُ الْمُلْكِ','Maalik Ul Mulk','মালিক-উল-মুলক','সকল সার্বভৌম শক্তির অধিকারী','');
INSERT INTO allah_names VALUES(85,'That is, Allah is the One who is better than any other in reality and all the evidence confirms this and denies the contrary so it is not valid to dispute this point, to deny it or to be hostile against this subject; is the One who fills with blessings those who will have understood this who will know the general holiness, will have success and will be well guided on the Day of Judgment','Possessor of Majesty and Bounty','(55:27)(55:78)','ذُوالْجَلاَلِ وَالإكْرَامِ','Dhu Al Jalaali Wa Al Ikraam','যুলজালালি-ওয়াল-ইকরাম','মহিমাময় ও মহানুভব','');
INSERT INTO allah_names VALUES(86,'Is the One who judges according to the greatest justice, the One who is free from all forms of injustice and tyranny, and the One who has absolutely no accountability','The Equitable One','(7:29)(3:18)','الْمُقْسِطُ','Al Muqsit','আল-মুকসিত','সুবিচারকারী','');
INSERT INTO allah_names VALUES(87,'Is the One who gathers creatures together on a day of which there is no doubt, the Day of Judgment','The Gatherer','(3:9)','الْجَامِعُ','Al Jaami''','আল-জামী','একত্রিতকারী','');
INSERT INTO allah_names VALUES(88,'Is the One who has no need of creatures and whose creatures cannot do without al-Ghaniyy [who is the One who makes them exist and keeps them in existence and constantly changes them]','The Rich One','(3:97)(39:7)(47:38)(57:24)','الْغَنِيُّ','Al Ghaniyy','আল-গানী','ধনী / অমুখাপেক্ষী','');
INSERT INTO allah_names VALUES(89,'Is the One who satisfies the needs of creatures and the One who brings them their sustenance','The Enricher','(9:28)','الْمُغْنِي','Al Mughi','আল-মুগনী','ধন দানকারী / অভাবমুক্তকারী','');
INSERT INTO allah_names VALUES(90,'Is the One who intends for each creature his victories, his protections and the One from whom they must always be preserved according to a destiny','The Preventer of harm','(67:21)','اَلْمَانِعُ','Al Maani''','আল-মানীই','বারণকারী / হারাম থেকে নিষেধকারী','');
INSERT INTO allah_names VALUES(91,'Is the One who is almighty to bring inevitably the nuisance which must reach a creature according to a destiny','The Creator of the harmful','(6:17)','الضَّارَّ','Ad Daaarr','আদ-দার্‌রু','অপকার করার মালিক','');
INSERT INTO allah_names VALUES(92,'Is the One who is almighty to bring inevitably the profit that a creature must receive according to a destiny','The Bestower of Benefits','(30:37)','النَّافِعُ','An Naafi’','আন-নাফী','উপকার করার মালিক','');
INSERT INTO allah_names VALUES(93,'The Light: Is the One who guides to their goal those who are prey to temptation and puts them in the right direction according to a destiny; Allah is the One who guides believers to the light of faith, creates light and is not a light that is only a creature','The Light','(24:35)','النُّورُ','An Noor','আন-নূর','নূর দানকারী','');
INSERT INTO allah_names VALUES(94,'Is the One who intends for certain creatures the benefit of being well guided and of knowing righteousness','The Guider','(25:31)','الْهَادِي','Al Haadi','আল-হাদী','পথপ্রদর্শক','');
INSERT INTO allah_names VALUES(95,'Is the One who brings creatures and this world into existence, not from pre-existing matter or in the image of an earlier model, but on the contrary without precursor, model and unprecedented','The Incomparable Originator','(2:117)(6:101)','الْبَدِيعُ','Al Badi''','আল-বাদীই','বিনা নমুনাতে সৃষ্টির অধিকারী','');
INSERT INTO allah_names VALUES(96,'Is the One whose existence free from annihilation and change is imposed on sound reason which cannot claim the contrary','The Everlasting One','(55:27)','اَلْبَاقِي','Al Baaqi','আল-বাকী','চিরস্থায়ী','');
INSERT INTO allah_names VALUES(97,'Is the One who exists and does not change as creatures are wiped out','The Inhertior','(15:23)','الْوَارِثُ','Al Waarith','আল-ওয়ারিস','সকলকিছুর উত্তরাধিকারী','');
INSERT INTO allah_names VALUES(98,'Is the One who guides creatures to what is in their best interests','The Most Righteous Guide','(2:256)','الرَّشِيدُ','Ar Rasheed','আর-রাশিদ','সৎপথ প্রদর্শনকারী','');
INSERT INTO allah_names VALUES(99,'Is the One who delays the punishment of sinners by adjusting the accounts of each until a definite day and gives them their ease and time until a time of which they all do not know the date.','The Patient One','(2:153)(3:200)(103:3)','الصَّبُورُ','As Saboor','আস-সাবুর','ধৈর্যশীল ও সহিষ্ণু','');
